export const legacyMarkup = "<div class=\"cursor\" id=\"cursor\"></div>\r\n<div class=\"cursor-dot\" id=\"cursorDot\"></div>\r\n\r\n<!-- NAVIGATION -->\r\n<nav>\r\n  <div class=\"nav-logo\">Chhatrapati Chhatrapati Shivaji Maharaj</div>\r\n  <ul class=\"nav-links\">\r\n    <li><a href=\"#early-life\">Early Life</a></li>\r\n    <li><a href=\"#timeline\">Timeline</a></li>\r\n    <li><a href=\"#battles\">Battles</a></li>\r\n    <li><a href=\"#forts\">Forts</a></li>\r\n    <li><a href=\"#coronation\">Coronation</a></li>\n    <li><a href=\"#videos\">Videos</a></li>\n    <li><a href=\"#legacy\">Legacy</a></li>\n    <li><a href=\"#guestbook\">Guestbook</a></li>\n  </ul>\n</nav>\n\r\n<!-- HERO -->\r\n<section id=\"hero\">\r\n  <div class=\"hero-bg-pattern\"></div>\r\n  <div class=\"hero-rays\"></div>\r\n  <div class=\"hero-glow\"></div>\r\n  <div class=\"hero-content\">\r\n    <div class=\"hero-subtitle-top\">The Great Maratha King</div>\r\n    <div class=\"hero-emblem\"></div>\r\n    <h1 class=\"hero-title\">Chhatrapati<br>Shivaji Maharaj</h1>\r\n    <div class=\"hero-title-sub\">छत्रपती शिवाजी महाराज</div>\r\n    <div class=\"hero-dates\">19 February 1630 — 3 April 1680</div>\r\n    <p class=\"hero-tagline\">\"The Founder of the Maratha Empire, the Lion of the Sahyadris, the Champion of Swarajya — a warrior whose valor echoes through eternity.\"</p>\r\n    <div class=\"hero-cta\">\r\n      <a href=\"#early-life\" class=\"btn-primary\">Explore His Story</a>\r\n      <a href=\"#timeline\" class=\"btn-secondary\">View Timeline</a>\r\n    </div>\r\n  </div>\r\n  <div class=\"scroll-indicator\">SCROLL</div>\r\n</section>\r\n\r\n<!-- EARLY LIFE -->\r\n<section id=\"early-life\">\r\n  <div class=\"section-container\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter I</span>\r\n      <h2 class=\"section-title\">Birth & Early Life</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">Born into valor, raised on stories of heroism, destined for greatness</p>\r\n    </div>\r\n\r\n    <div class=\"early-life-grid\">\r\n      <div class=\"reveal-left\">\r\n        <div class=\"early-life-image-wrap\">\n          <img class=\"early-life-img\"\n            src=\"assets/birth.png\"\n            alt=\"Birth of Chhatrapati Shivaji Maharaj at Shivneri Fort\">\n          <div class=\"birth-image-caption\">Birth at Shivneri Fort · 19 February 1630</div>\n        </div>\n      </div>\n\r\n      <div class=\"reveal-right\">\r\n        <div class=\"info-card\">\r\n          <h3>Birth</h3>\r\n          <p>Chhatrapati Shivaji Bhonsale was born on <strong style=\"color:var(--saffron)\">19 February 1630</strong> at the majestic <strong style=\"color:var(--gold)\">Shivneri Fort</strong> in the Pune district of Maharashtra. His mother Jijabai named him \"Shiva\" after the local goddess Shivai.</p>\r\n        </div>\r\n        <div class=\"info-card\">\r\n          <h3>Royal Parents</h3>\r\n          <p><strong style=\"color:var(--gold)\">Father: Shahaji Bhonsale</strong> — A Maratha military commander in the Deccan Sultanates.<br><strong style=\"color:var(--gold)\">Mother: Jijabai</strong> — A devout woman of remarkable strength who shaped Chhatrapati Chhatrapati Shivaji's character with tales of Ramayana and Mahabharata.</p>\r\n        </div>\r\n        <div class=\"info-card\">\r\n          <h3>Education & Upbringing</h3>\r\n          <p>Raised primarily by his mother Jijabai and mentor <strong style=\"color:var(--gold)\">Dadoji Kondadev</strong>, Chhatrapati Shivaji learned administration, governance, military tactics, and developed deep Hindu values and justice. He grew up with Mavala companions who would later form the core of his army.</p>\r\n        </div>\r\n\r\n        <div class=\"birth-stats\">\r\n          <div class=\"stat-box\">\r\n            <span class=\"val\">1630</span>\r\n            <span class=\"lbl\">Year of Birth</span>\r\n          </div>\r\n          <div class=\"stat-box\">\r\n            <span class=\"val\">Shivneri</span>\r\n            <span class=\"lbl\">Birthplace Fort</span>\r\n          </div>\r\n          <div class=\"stat-box\">\r\n            <span class=\"val\">16</span>\r\n            <span class=\"lbl\">Age at First Conquest</span>\r\n          </div>\r\n          <div class=\"stat-box\">\r\n            <span class=\"val\">360+</span>\r\n            <span class=\"lbl\">Forts in Empire</span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"numbers-bar reveal\">\r\n      <div class=\"number-item\">\r\n        <span class=\"number-val\">50</span>\r\n        <span class=\"number-label\">Years of Life</span>\r\n      </div>\r\n      <div class=\"number-item\">\r\n        <span class=\"number-val\">300+</span>\r\n        <span class=\"number-label\">Battles & Campaigns</span>\r\n      </div>\r\n      <div class=\"number-item\">\r\n        <span class=\"number-val\">360+</span>\r\n        <span class=\"number-label\">Forts Controlled</span>\r\n      </div>\r\n      <div class=\"number-item\">\r\n        <span class=\"number-val\">4.1M</span>\r\n        <span class=\"number-label\">km² at Peak</span>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"reveal\" style=\"background:rgba(255,107,0,0.04);border:1px solid rgba(212,160,23,0.1);padding:40px;max-width:800px;margin:0 auto;\">\r\n      <h3 style=\"font-family:'Cinzel',serif;color:var(--gold);font-size:1rem;letter-spacing:2px;margin-bottom:20px;text-align:center;\"> THE VISION OF SWARAJYA</h3>\r\n      <p style=\"font-family:'EB Garamond',serif;font-size:1.15rem;line-height:1.9;color:var(--text-muted);text-align:center;\">\r\n        From his earliest years, young Chhatrapati Shivaji dreamed of an independent homeland — <em style=\"color:var(--cream)\">Swarajya</em> (self-rule) for the Maratha people. Under the inspiration of his mother Jijabai and the epics of the Ramayana, he vowed to create a kingdom free from foreign domination. This dream would shape every decision of his extraordinary life.\r\n      </p>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- TIMELINE -->\r\n<section id=\"timeline\">\r\n  <div class=\"section-watermark\">SWARAJYA</div>\r\n  <div class=\"section-container\" style=\"position:relative;z-index:1;\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter II</span>\r\n      <h2 class=\"section-title\">The Life Timeline</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">From a young prince to a legendary emperor — the milestones of a remarkable journey</p>\r\n    </div>\r\n\r\n    <div class=\"timeline-items\" style=\"position:relative;\">\r\n      <div class=\"timeline-line\"></div>\r\n\r\n      <!-- Timeline Items -->\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-content-left\">\r\n          <div class=\"timeline-year\">1630</div>\r\n          <div class=\"timeline-event-title\">Birth at Shivneri</div>\r\n          <p class=\"timeline-event-desc\">Born on February 19 at Shivneri Fort. Mother Jijabai names him after the goddess Shivai. His destiny is whispered in the winds of the Sahyadris.</p>\r\n        </div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-empty\"></div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-empty\"></div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-content-right\">\r\n          <div class=\"timeline-year\">1636–1645</div>\r\n          <div class=\"timeline-event-title\">Formative Years in Pune</div>\r\n          <p class=\"timeline-event-desc\">Raised by Jijabai and Dadoji Kondadev in Pune. Learns military arts, administration and the Vedas. Forms deep friendships with Mavala companions — Tanaji Malusare, Yesaji Kank, and others.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-content-left\">\r\n          <div class=\"timeline-year\">1645–47</div>\r\n          <div class=\"timeline-event-title\">First Fort — Torna!</div>\r\n          <p class=\"timeline-event-desc\">At just 16 years old, Chhatrapati Shivaji captures Torna Fort from Bijapur Sultanate — his first act of swarajya. He uses the treasury found inside to build Rajgad Fort. The lion has awakened.</p>\r\n        </div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-empty\"></div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-empty\"></div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-content-right\">\r\n          <div class=\"timeline-year\">1656</div>\r\n          <div class=\"timeline-event-title\">Marriage & Alliances</div>\r\n          <p class=\"timeline-event-desc\">Chhatrapati Shivaji marries Saibai Nimbalkar among other wives. He strategically expands his territory, capturing Javali from Chandrarao More — a crucial step in consolidating the Sahyadri region.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-content-left\">\r\n          <div class=\"timeline-year\">1659</div>\r\n          <div class=\"timeline-event-title\">Battle of Pratapgad — Afzal Khan Slain!</div>\r\n          <p class=\"timeline-event-desc\">The defining moment. Bijapur sends the giant general Afzal Khan with 10,000 troops. In a private meeting, Chhatrapati Shivaji uses his wagh nakh (tiger claw) to kill Afzal Khan. Maratha forces annihilate the Bijapur army. Legend is born.</p>\r\n        </div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-empty\"></div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-empty\"></div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-content-right\">\r\n          <div class=\"timeline-year\">1660</div>\r\n          <div class=\"timeline-event-title\">Battle of Pavan Khind</div>\r\n          <p class=\"timeline-event-desc\">Chhatrapati Shivaji retreats through Pavan Khind (Vishalgad). Baji Prabhu Deshpande and 300 Marathas hold the narrow pass against 10,000 Adilshahi soldiers, sacrificing their lives until Chhatrapati Shivaji reaches safety. Immortal heroism.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-content-left\">\r\n          <div class=\"timeline-year\">1663</div>\r\n          <div class=\"timeline-event-title\">Night Raid on Shaista Khan</div>\r\n          <p class=\"timeline-event-desc\">Mughal viceroy Shaista Khan occupies Pune. Chhatrapati Shivaji leads a daring 400-man night raid through a wedding procession into Shaista Khan's bedroom. Khan barely escapes, losing his fingers. Aurangzeb is humiliated.</p>\r\n        </div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-empty\"></div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-empty\"></div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-content-right\">\r\n          <div class=\"timeline-year\">1664</div>\r\n          <div class=\"timeline-event-title\">Sack of Surat</div>\r\n          <p class=\"timeline-event-desc\">Chhatrapati Shivaji storms Surat — the wealthiest Mughal port — looting it to fund the Maratha cause. The English and Dutch factories are spared. The Mughal empire reels. Aurangzeb dispatches his best general: Jai Singh.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-content-left\">\r\n          <div class=\"timeline-year\">1666</div>\r\n          <div class=\"timeline-event-title\">The Great Escape from Agra!</div>\r\n          <p class=\"timeline-event-desc\">Summoned to Aurangzeb's court in Agra, Chhatrapati Shivaji is placed under house arrest. In the most daring escape of his life, he hides in fruit baskets and flees — a 2,000 km journey back to Maharashtra. The entire Mughal empire searches for him in vain.</p>\r\n        </div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-empty\"></div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-empty\"></div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-content-right\">\r\n          <div class=\"timeline-year\">1670</div>\r\n          <div class=\"timeline-event-title\">Recapture & Second Sack of Surat</div>\r\n          <p class=\"timeline-event-desc\">Chhatrapati Shivaji recaptures most forts lost in the Treaty of Purandar in just 45 days. He sacks Surat a second time, further funding his growing empire. The Maratha navy is rapidly expanding.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-content-left\">\r\n          <div class=\"timeline-year\">1674</div>\r\n          <div class=\"timeline-event-title\">CORONATION — Chhatrapati!</div>\r\n          <p class=\"timeline-event-desc\">On June 6, 1674 at Raigad Fort, Chhatrapati Shivaji is crowned Chhatrapati (Emperor) in a grand ceremony performed by Pandit Gagabhatt of Varanasi. Swarajya is officially born. The Maratha Empire stands as a sovereign Hindu kingdom.</p>\r\n        </div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-empty\"></div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-empty\"></div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-content-right\">\r\n          <div class=\"timeline-year\">1674–80</div>\r\n          <div class=\"timeline-event-title\">Southern Campaigns</div>\r\n          <p class=\"timeline-event-desc\">Chhatrapati Shivaji launches campaigns into Karnataka and Tamil Nadu. The Battle of Jinji (1677) extends Maratha influence deep into the south. He meets Sambhaji, his son who is to succeed him, and works to consolidate the vast empire.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"timeline-item reveal\">\r\n        <div class=\"timeline-content-left\">\r\n          <div class=\"timeline-year\">1680</div>\r\n          <div class=\"timeline-event-title\">Departure of the Lion</div>\r\n          <p class=\"timeline-event-desc\">On April 3, 1680, Chhatrapati Shivaji Maharaj passed away at Raigad Fort at the age of 50. He left behind a vast empire, a powerful navy, a just administration — and an eternal legacy that inspired all future freedom struggles of India.</p>\r\n        </div>\r\n        <div class=\"timeline-node\"></div>\r\n        <div class=\"timeline-empty\"></div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- BATTLES SECTION -->\r\n<section id=\"battles\">\r\n  <div class=\"section-container\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter III</span>\r\n      <h2 class=\"section-title\">Battles for Swarajya</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">Every battle a story of impossible courage, tactical brilliance and undying spirit</p>\r\n    </div>\r\n\r\n    <!-- Animated Battle Scene -->\r\n    <div class=\"battle-animation-section reveal\">\r\n      <h3 style=\"font-family:'Cinzel',serif;color:var(--gold);letter-spacing:3px;margin-bottom:20px;\"> THE MARATHA SPIRIT IN BATTLE</h3>\r\n      <div class=\"swords-animation\">\r\n        <div class=\"warrior warrior-maratha\">\r\n          <div class=\"warrior-figure\"></div>\r\n          <div class=\"warrior-label\">MARATHA WARRIORS</div>\r\n          <div style=\"font-family:'Cinzel',serif;font-size:0.65rem;color:var(--saffron);letter-spacing:1px;text-align:center;\">JAY BHAVANI!</div>\r\n        </div>\r\n        <div class=\"vs-text\">VS</div>\r\n        <div class=\"warrior warrior-enemy\">\r\n          <div class=\"warrior-figure\"></div>\r\n          <div class=\"warrior-label\">MUGHAL / BIJAPUR FORCES</div>\r\n          <div style=\"font-family:'Cinzel',serif;font-size:0.65rem;color:var(--text-muted);letter-spacing:1px;text-align:center;\">10x Larger Armies</div>\r\n        </div>\r\n      </div>\r\n      <div class=\"inline-quote\" style=\"max-width:600px;margin:20px auto 0;\">\r\n        \"Chhatrapati Shivaji never fought a fair battle — he always fought smart battles. Guerrilla warfare, night raids, mountain passes — the land itself was his ally.\"\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"battles-grid\">\r\n\r\n      <!-- Battle 1 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <img class=\"battle-bg\"\r\n            src=\"assets/Pratapgad.png\"\n            alt=\"Battle of Pratapgad\"\r\n            onerror=\"this.style.background='linear-gradient(135deg,#3D0008,#1A0A00)'\">\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1659</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Battle of Pratapgad</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Pratapgad Fort</span>\r\n            <span> Vs. Bijapur Sultanate</span>\r\n          </div>\r\n          <p class=\"battle-desc\">The most dramatic battle of Chhatrapati Chhatrapati Shivaji's life. Afzal Khan, a giant Bijapur general, led 10,000 troops to crush Chhatrapati Shivaji. In a private meeting, Chhatrapati Shivaji killed Afzal Khan with his wagh nakh (tiger claws) hidden under his armor. Maratha forces then ambushed the leaderless Bijapur army. A complete Maratha victory that shocked the entire Deccan.</p>\r\n          <span class=\"battle-result victory\"> DECISIVE VICTORY</span>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Battle 2 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <img class=\"battle-bg\"\r\n            src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d5/Pavan_khind.jpg/800px-Pavan_khind.jpg\"\r\n            alt=\"Battle of Pavan Khind\"\r\n            onerror=\"this.style.background='linear-gradient(135deg,#1A0000,#0D0500)'\">\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1660</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Battle of Pavan Khind</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Ghod Khind Pass</span>\r\n            <span> Vs. Siddi Masud</span>\r\n          </div>\r\n          <p class=\"battle-desc\">Surrounded by 10,000 Bijapur soldiers, Chhatrapati Shivaji needed to escape to Vishalgad. Brave Baji Prabhu Deshpande volunteered to hold the narrow Ghod Khind pass with just 300 soldiers. He fought until he heard the victory cannon of Vishalgad Fort — then fell. This sacrifice is one of the greatest in Maratha history.</p>\r\n          <span class=\"battle-result victory\"> CHHATRAPATI SHIVAJI ESCAPED SAFELY</span>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Battle 3 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <div style=\"width:100%;height:100%;background:linear-gradient(135deg,#1A0500,#3D1000);display:flex;align-items:center;justify-content:center;font-size:5rem;\"></div>\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1663</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Raid on Shaista Khan</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Lal Mahal, Pune</span>\r\n            <span> Vs. Mughal Viceroy</span>\r\n          </div>\r\n          <p class=\"battle-desc\">Mughal viceroy Shaista Khan had occupied Pune. Chhatrapati Shivaji led just 400 men disguised as a wedding procession at night. They scaled the walls and attacked the palace. Shaista Khan barely escaped by jumping out a window, losing three fingers. The Mughals were humiliated and Khan was transferred to Bengal in disgrace.</p>\r\n          <span class=\"battle-result victory\"> AUDACIOUS VICTORY</span>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Battle 4 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <div style=\"width:100%;height:100%;background:linear-gradient(135deg,#001A3D,#000D26);display:flex;align-items:center;justify-content:center;font-size:5rem;\"></div>\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1664</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Sack of Surat (First)</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Surat Port</span>\r\n            <span> Vs. Mughal Empire</span>\r\n          </div>\r\n          <p class=\"battle-desc\">Surat was the richest city in Mughal India and their main port. Chhatrapati Shivaji attacked with 4,000 cavalry and looted the city for 4 days, accumulating enormous wealth to fund his campaigns. He deliberately spared the English and Dutch factories, showing diplomatic wisdom. Mughal prestige was severely damaged.</p>\r\n          <span class=\"battle-result victory\"> STRATEGIC VICTORY</span>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Battle 5 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <img class=\"battle-bg\"\r\n            src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/9/96/Battle_of_Kolhapur.jpg/800px-Battle_of_Kolhapur.jpg\"\r\n            alt=\"Battle of Kolhapur\"\r\n            onerror=\"this.style.background='linear-gradient(135deg,#2A0000,#0D0000)'\">\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1659</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Battle of Kolhapur</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Kolhapur Region</span>\r\n            <span> Vs. Bijapur Army</span>\r\n          </div>\r\n          <p class=\"battle-desc\">After Pratapgad, Bijapur sent another general — Rustam Zaman — with a fresh army. Chhatrapati Shivaji met them at Kolhapur and delivered another crushing defeat. The Bijapur cavalry was scattered and the Maratha empire expanded significantly in the southern Deccan. Two decisive victories in a single year sent a clear message to all opponents.</p>\r\n          <span class=\"battle-result victory\"> COMPLETE VICTORY</span>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Battle 6 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <img class=\"battle-bg\"\r\n            src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b5/Battle_of_Salher.jpg/800px-Battle_of_Salher.jpg\"\r\n            alt=\"Battle of Salher\"\r\n            onerror=\"this.style.background='linear-gradient(135deg,#001A00,#000D00)'\">\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1672</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Battle of Salher</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Salher Fort, Nashik</span>\r\n            <span> Vs. Mughal Army</span>\r\n          </div>\r\n          <p class=\"battle-desc\">The largest open-field battle Chhatrapati Shivaji ever fought. Mughal forces laid siege to Salher Fort. Chhatrapati Shivaji sent his generals Prataprao Gujar and Moropant Trimbak Pingle who defeated the Mughal army of 40,000 men in an open pitched battle. Over 6,000 Mughal soldiers were killed and thousands captured. One of Maratha history's greatest military triumphs.</p>\r\n          <span class=\"battle-result victory\"> LANDMARK VICTORY</span>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Battle 7 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <div style=\"width:100%;height:100%;background:linear-gradient(135deg,#1A1500,#0D0A00);display:flex;align-items:center;justify-content:center;font-size:5rem;\"></div>\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1665</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Treaty of Purandar</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Purandar Fort</span>\r\n            <span> Jai Singh I (Mughal)</span>\r\n          </div>\r\n          <p class=\"battle-desc\">Aurangzeb sent Raja Jai Singh of Amber with a massive army. After fierce resistance, Chhatrapati Shivaji signed the Treaty of Purandar — surrendering 23 forts and 400,000 hun. A tactical retreat, not a defeat. Chhatrapati Shivaji later recaptured all forts within months. He would never surrender his spirit, only bide his time.</p>\r\n          <span class=\"battle-result strategic\"> STRATEGIC RETREAT</span>\r\n        </div>\r\n      </div>\r\n\r\n      <!-- Battle 8 -->\r\n      <div class=\"battle-card reveal\">\r\n        <div class=\"battle-img-wrap\">\r\n          <div style=\"width:100%;height:100%;background:linear-gradient(135deg,#0D001A,#050008);display:flex;align-items:center;justify-content:center;font-size:5rem;\"></div>\r\n          <div class=\"battle-img-overlay\"></div>\r\n          <div class=\"battle-year-badge\">1666</div>\r\n        </div>\r\n        <div class=\"battle-content\">\r\n          <div class=\"battle-name\">Escape from Agra</div>\r\n          <div class=\"battle-meta\">\r\n            <span> Agra → Raigad</span>\r\n            <span> Mughal Empire</span>\r\n          </div>\r\n          <p class=\"battle-desc\">Invited to Aurangzeb's court in Agra, Chhatrapati Shivaji was placed under house arrest. In one of history's most daring escapes, he faked illness and used fruit basket deliveries to smuggle himself out — then traveled 2,000 km back to Maharashtra disguised as a saint. The Mughal empire was humiliated. The return of Chhatrapati Shivaji energized all of Maharashtra.</p>\r\n          <span class=\"battle-result victory\"> LEGENDARY ESCAPE</span>\r\n        </div>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- FORTS SECTION -->\r\n<section id=\"forts\">\r\n  <div class=\"section-container\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter IV</span>\r\n      <h2 class=\"section-title\">Forts of the Maratha Empire</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">Stone guardians of Swarajya — each fort a chapter in the story of freedom</p>\r\n    </div>\r\n\r\n    <div class=\"forts-grid\">\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"assets/Raigad.png\"\n          alt=\"Raigad Fort\"\r\n          onerror=\"this.style.background='#1A0A00'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Raigad Fort</div>\r\n          <div class=\"fort-year\">Capital of Maratha Empire</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"assets/Shivneri.png\"\n          alt=\"Shivneri Fort\"\r\n          onerror=\"this.style.background='#0D1A00'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Shivneri Fort</div>\r\n          <div class=\"fort-year\">Birthplace of Chhatrapati Shivaji — 1630</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"assets/Pratapgad.png\"\n          alt=\"Pratapgad Fort\"\r\n          onerror=\"this.style.background='#1A0500'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Pratapgad Fort</div>\r\n          <div class=\"fort-year\">Site of Afzal Khan's defeat — 1659</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/3/35/Sindhudurg_Fort.jpg/800px-Sindhudurg_Fort.jpg\"\r\n          alt=\"Sindhudurg Fort\"\r\n          onerror=\"this.style.background='#001A1A'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Sindhudurg Fort</div>\r\n          <div class=\"fort-year\">Sea Fort — Built 1664–67</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/e/e2/Torna_fort.jpg/800px-Torna_fort.jpg\"\r\n          alt=\"Torna Fort\"\r\n          onerror=\"this.style.background='#0D0D00'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Torna Fort</div>\r\n          <div class=\"fort-year\">First Conquest — 1645</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"assets/Sinhgad.png\"\n          alt=\"Sinhagad Fort\"\r\n          onerror=\"this.style.background='#001A0D'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Sinhagad Fort</div>\r\n          <div class=\"fort-year\">Tanaji's Sacrifice — 1670</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"assets/Rajgad.png\"\n          alt=\"Rajgad Fort\"\r\n          onerror=\"this.style.background='#1A0005'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Rajgad Fort</div>\r\n          <div class=\"fort-year\">First Capital — 1648–70</div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"fort-card reveal\">\r\n        <img class=\"fort-img\"\r\n          src=\"https://upload.wikimedia.org/wikipedia/commons/thumb/0/04/Vijaydurg_fort.jpg/800px-Vijaydurg_fort.jpg\"\r\n          alt=\"Vijaydurg Fort\"\r\n          onerror=\"this.style.background='#00001A'\">\r\n        <div class=\"fort-overlay\"></div>\r\n        <div class=\"fort-info\">\r\n          <div class=\"fort-name\">Vijaydurg Fort</div>\r\n          <div class=\"fort-year\">Naval Headquarters</div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"reveal\" style=\"text-align:center;margin-top:40px;\">\r\n      <div class=\"inline-quote\" style=\"max-width:700px;margin:0 auto;\">\r\n        \"Chhatrapati Chhatrapati Shivaji Maharaj maintained over 360 forts — from the Sahyadri mountains to the Konkan coast. Each fort was a symbol of Maratha sovereignty and a bastion of Swarajya.\"\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- CORONATION -->\r\n<section id=\"coronation\">\r\n  <div class=\"section-container\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter V</span>\r\n      <h2 class=\"section-title\">The Grand Coronation</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">June 6, 1674 — The day Swarajya became a reality</p>\r\n    </div>\r\n\r\n    <div class=\"coronation-main\">\r\n      <div class=\"coronation-facts reveal-left\">\r\n        <div class=\"maratha-seal\"></div>\r\n\r\n        <div class=\"coronation-fact-item\">\r\n          <div class=\"fact-icon\"></div>\r\n          <div class=\"fact-text\">\r\n            <h4>Date of Coronation</h4>\r\n            <p>June 6, 1674 (Jyeshtha Shukla Trayodashi, Ananda Samvatsara) at Raigad Fort. An auspicious day selected by Pandit Gagabhatt of Varanasi after elaborate calculations.</p>\r\n          </div>\r\n        </div>\r\n\r\n        <div class=\"coronation-fact-item\">\r\n          <div class=\"fact-icon\"></div>\r\n          <div class=\"fact-text\">\r\n            <h4>Location — Raigad Fort</h4>\r\n            <p>Raigad (also called Rairi) became the new capital. Perched 820 meters above sea level, it was an impregnable mountain fortress overlooking the Konkan. Chhatrapati Shivaji himself designed the city of Pachad at its base.</p>\r\n          </div>\r\n        </div>\r\n\r\n        <div class=\"coronation-fact-item\">\r\n          <div class=\"fact-icon\"></div>\r\n          <div class=\"fact-text\">\r\n            <h4>The Ceremony</h4>\r\n            <p>Pandit Gagabhatt performed the Vedic coronation rituals. Chhatrapati Shivaji was anointed with holy waters from all the sacred rivers of India. He was crowned with a gem-studded crown and given the titles <em>Chhatrapati, Shakakarta, Kshatriya Kulavantas, Haindava Dharmoddhaarak</em>.</p>\r\n          </div>\r\n        </div>\r\n\r\n        <div class=\"coronation-fact-item\">\r\n          <div class=\"fact-icon\"></div>\r\n          <div class=\"fact-text\">\r\n            <h4>Historic Significance</h4>\r\n            <p>After over 300 years of Muslim sultanate rule, a Hindu Maratha king sat on a sovereign throne. 50,000+ people attended. It wasn't just a coronation — it was the rebirth of a civilization's pride. Even the English East India Company sent envoys.</p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"reveal-right\">\r\n        <div class=\"coronation-quote-bg\">\r\n          <p class=\"coronation-quote-text\">\r\n            \"Chhatrapati Chhatrapati Shivaji's coronation was not merely a political event — it was a renaissance. For a people crushed under centuries of foreign rule, it was the moment they dared to believe again. The lion had not just conquered territory; he had conquered the imagination of an entire civilization.\"\r\n          </p>\r\n          <div class=\"coronation-quote-author\">— Historical Analysis of the Maratha Renaissance</div>\r\n        </div>\r\n\r\n        <div style=\"margin-top:30px;display:grid;grid-template-columns:1fr 1fr;gap:15px;\">\r\n          <div class=\"stat-box\" style=\"padding:25px;\">\r\n            <span class=\"val\" style=\"font-size:1.2rem;\">50,000+</span>\r\n            <span class=\"lbl\">Attendees</span>\r\n          </div>\r\n          <div class=\"stat-box\" style=\"padding:25px;\">\r\n            <span class=\"val\" style=\"font-size:1.2rem;\">June 6</span>\r\n            <span class=\"lbl\">Coronation Day</span>\r\n          </div>\r\n          <div class=\"stat-box\" style=\"padding:25px;\">\r\n            <span class=\"val\" style=\"font-size:1.2rem;\">1674</span>\r\n            <span class=\"lbl\">Year of Swarajya</span>\r\n          </div>\r\n          <div class=\"stat-box\" style=\"padding:25px;\">\r\n            <span class=\"val\" style=\"font-size:1.2rem;\">820m</span>\r\n            <span class=\"lbl\">Raigad Altitude</span>\r\n          </div>\r\n        </div>\r\n\r\n        <div style=\"margin-top:20px;background:rgba(255,107,0,0.05);border:1px solid rgba(255,107,0,0.2);padding:25px;\">\r\n          <h4 style=\"font-family:'Cinzel',serif;color:var(--saffron);font-size:0.8rem;letter-spacing:2px;margin-bottom:12px;\">ROYAL TITLES BESTOWED</h4>\r\n          <p style=\"font-family:'EB Garamond',serif;font-size:1rem;color:var(--text-muted);line-height:1.8;\">\r\n             <strong style=\"color:var(--cream)\">Chhatrapati</strong> — Lord of the Parasol (Emperor)<br>\r\n             <strong style=\"color:var(--cream)\">Shakakarta</strong> — Creator of a New Era<br>\r\n             <strong style=\"color:var(--cream)\">Kshatriya Kulavantas</strong> — Head of the Kshatriya Clan<br>\r\n             <strong style=\"color:var(--cream)\">Haindava Dharmoddhaarak</strong> — Protector of Hindu Dharma\r\n          </p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- ACHIEVEMENTS & ADMINISTRATION -->\r\n<section id=\"achievements\">\r\n  <div class=\"section-container\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter VI</span>\r\n      <h2 class=\"section-title\">The Architect of an Empire</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">Beyond battles — the administration, navy, and governance that made Swarajya great</p>\r\n    </div>\r\n\r\n    <div class=\"achievements-grid\">\r\n      <div class=\"achievement-card reveal\">\r\n        <span class=\"achievement-icon\"></span>\r\n        <div class=\"achievement-title\">Father of the Indian Navy</div>\r\n        <p class=\"achievement-desc\">Chhatrapati Shivaji was the first Indian ruler to build and maintain a powerful naval force. His Maratha Navy had over 200 warships — Ghurabs and Gallivats — patrolling the Konkan coast. He built sea forts like Sindhudurg, Vijaydurg, and Jaigad. He is officially recognized as the \"Father of the Indian Navy.\"</p>\r\n      </div>\r\n\r\n      <div class=\"achievement-card reveal\">\r\n        <span class=\"achievement-icon\"></span>\r\n        <div class=\"achievement-title\">Just & Secular Governance</div>\r\n        <p class=\"achievement-desc\">Chhatrapati Shivaji ran a remarkably just administration. He treated all religions with equal respect — many Muslims served in high positions in his army and court. He never allowed desecration of mosques or temples in conquered territories. He treated captured women with utmost dignity — even when his own soldiers found royal women of enemy kings, he returned them with honor.</p>\r\n      </div>\r\n\r\n      <div class=\"achievement-card reveal\">\r\n        <span class=\"achievement-icon\"></span>\r\n        <div class=\"achievement-title\">Ashtapradhan Mandal</div>\r\n        <p class=\"achievement-desc\">Chhatrapati Shivaji created the Ashtapradhan (council of eight ministers) system — an unprecedented administrative structure. Each minister had a specific portfolio: Peshwa (PM), Amatya (Finance), Mantri (Records), Senapati (Military), Nyayadhish (Justice), Panditrao (Religious), Sachiv (Correspondence), and Shumantra (Foreign Affairs).</p>\r\n      </div>\r\n\r\n      <div class=\"achievement-card reveal\">\r\n        <span class=\"achievement-icon\"></span>\r\n        <div class=\"achievement-title\">Revenue Reform (Ryotwari)</div>\r\n        <p class=\"achievement-desc\">Chhatrapati Shivaji abolished the Jagirdari system. He introduced direct revenue collection from farmers (Ryotwari) — eliminating the exploitative middlemen. He measured land using a standardized unit (the kathi) and fixed fair taxes. He forgave revenue during famines and provided farmers with seeds, loans, and animals to rebuild.</p>\r\n      </div>\r\n\r\n      <div class=\"achievement-card reveal\">\r\n        <span class=\"achievement-icon\"></span>\r\n        <div class=\"achievement-title\">Guerrilla Warfare Pioneer</div>\r\n        <p class=\"achievement-desc\">Chhatrapati Shivaji perfected Ganimi Kava (guerrilla warfare) — using the Sahyadri mountains, jungles, and narrow passes to defeat much larger armies. He trained small, swift cavalry units (Mavale) who could strike and disappear like lightning. His tactics were so advanced, they are still studied in modern military academies worldwide.</p>\r\n      </div>\r\n\r\n      <div class=\"achievement-card reveal\">\r\n        <span class=\"achievement-icon\"></span>\r\n        <div class=\"achievement-title\">Language & Culture</div>\r\n        <p class=\"achievement-desc\">Chhatrapati Shivaji replaced Persian with Marathi and Sanskrit as the official languages of his court. He created a Sanskrit-based dictionary of administrative terms called \"Rajyavyavahar Kosh.\" He was a deep scholar of the Vedas, and commissioned the construction of many temples. He championed Marathi identity at a time when it was being suppressed.</p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- VIDEO SECTION -->\r\n<section id=\"videos\">\r\n  <div class=\"section-container\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter VII</span>\r\n      <h2 class=\"section-title\">Watch & Learn</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">Documentaries, historical analyses and storytelling about Chhatrapati Shivaji Maharaj</p>\r\n    </div>\r\n\r\n    <div class=\"videos-grid\">\r\n      <div class=\"video-wrap reveal\">\r\n        <iframe class=\"video-frame\"\r\n          src=\"https://www.youtube.com/embed/0GqbPeFmNJI\"\r\n          title=\"Chhatrapati Chhatrapati Shivaji Maharaj Full History\"\r\n          allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\"\r\n          allowfullscreen loading=\"lazy\"></iframe>\r\n        <div class=\"video-title\">Chhatrapati Shivaji Maharaj — Complete History</div>\r\n      </div>\r\n\r\n      <div class=\"video-wrap reveal\">\r\n        <iframe class=\"video-frame\"\r\n          src=\"https://www.youtube.com/embed/OJd1y7F8KLM\"\r\n          title=\"Battle of Pratapgad\"\r\n          allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\"\r\n          allowfullscreen loading=\"lazy\"></iframe>\r\n        <div class=\"video-title\">Battle of Pratapgad — Afzal Khan's Defeat</div>\r\n      </div>\r\n\r\n      <div class=\"video-wrap reveal\">\r\n        <iframe class=\"video-frame\"\r\n          src=\"https://www.youtube.com/embed/BqDqnSsPEhU\"\r\n          title=\"Chhatrapati Shivaji Coronation\"\r\n          allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\"\r\n          allowfullscreen loading=\"lazy\"></iframe>\r\n        <div class=\"video-title\">The Coronation of Chhatrapati Shivaji Maharaj</div>\r\n      </div>\r\n\r\n      <div class=\"video-wrap reveal\">\r\n        <iframe class=\"video-frame\"\r\n          src=\"https://www.youtube.com/embed/ydXbBVWqxgg\"\r\n          title=\"Chhatrapati Shivaji Escape from Agra\"\r\n          allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\"\r\n          allowfullscreen loading=\"lazy\"></iframe>\r\n        <div class=\"video-title\">The Daring Escape from Aurangzeb's Agra</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- PASSING -->\r\n<section id=\"passing\">\r\n  <div class=\"section-container\" style=\"position:relative;z-index:1;\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter VIII</span>\r\n      <h2 class=\"section-title\">The Lion's Last Breath</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">April 3, 1680 — A great light departed, but never faded</p>\r\n    </div>\r\n\r\n    <div class=\"passing-content\">\r\n      <div class=\"passing-text reveal-left\">\r\n        <h3>DEPARTURE OF THE CHHATRAPATI</h3>\r\n        <p>In late March 1680, Chhatrapati Chhatrapati Shivaji Maharaj fell seriously ill at Raigad Fort. He had been suffering from fever and dysentery for several weeks. On <strong style=\"color:var(--gold)\">April 3, 1680</strong>, at the age of 50, the great Chhatrapati breathed his last.</p>\r\n        <p>His death plunged Maharashtra into grief. Fifty years of tireless struggle — founding a kingdom from nothing, fighting the greatest empires of his time, building institutions that would outlast him — had taken their toll. Yet the Maratha Empire he built would survive and grow for over 150 years after his passing.</p>\r\n        <p>Chhatrapati Shivaji was cremated at Raigad Fort. His samadhi (memorial) stands there to this day, visited by millions every year. His son <strong style=\"color:var(--gold)\">Sambhaji Maharaj</strong> succeeded him and continued the struggle against the Mughals.</p>\r\n        <div class=\"inline-quote\">\r\n          \"He did not just build a kingdom — he rebuilt a civilization. He proved that no empire is too powerful to challenge when a people have the will to be free.\"\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"reveal-right\">\r\n        <div class=\"memorial-box\">\r\n          <h3>The Chhatrapati Chhatrapati Shivaji Maharaj Legacy in Numbers</h3>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Born</span>\r\n            <span class=\"memorial-stat-val\">19 February 1630, Shivneri Fort</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Died</span>\r\n            <span class=\"memorial-stat-val\">3 April 1680, Raigad Fort</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Age</span>\r\n            <span class=\"memorial-stat-val\">50 years</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Reign as Chhatrapati</span>\r\n            <span class=\"memorial-stat-val\">1674 – 1680 (6 years)</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Forts Controlled</span>\r\n            <span class=\"memorial-stat-val\">360+ forts across Deccan</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Empire at Death</span>\r\n            <span class=\"memorial-stat-val\">4.1 million km² (Maratha Empire)</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Naval Fleet</span>\r\n            <span class=\"memorial-stat-val\">200+ warships</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Successor</span>\r\n            <span class=\"memorial-stat-val\">Sambhaji Maharaj (son)</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Dynasty</span>\r\n            <span class=\"memorial-stat-val\">Bhonsle (Maratha)</span>\r\n          </div>\r\n          <div class=\"memorial-stat\">\r\n            <span class=\"memorial-stat-key\">Capital</span>\r\n            <span class=\"memorial-stat-val\">Raigad Fort</span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\r\n\r\n<!-- LEGACY -->\r\n<section id=\"legacy\">\r\n  <div class=\"section-container\">\r\n    <div class=\"section-header reveal\">\r\n      <span class=\"section-label\">Chapter IX</span>\r\n      <h2 class=\"section-title\">An Eternal Legacy</h2>\r\n      <div class=\"section-divider\"></div>\r\n      <p class=\"section-desc\">His memory lives not in stone, but in the hearts of a billion people</p>\r\n    </div>\r\n\r\n    <div class=\"legacy-content reveal\">\r\n      <div class=\"legacy-quote\">\r\n        <p class=\"legacy-quote-text\">\"Chhatrapati Shivaji was one of the greatest national figures India has ever produced. He was a born leader of men, a reformer, and a great ruler. His personal courage was remarkable.\"</p>\r\n        <div class=\"legacy-quote-source\">— Jawaharlal Nehru, First Prime Minister of India</div>\r\n      </div>\r\n\r\n      <p class=\"legacy-para\">Chhatrapati Shivaji Maharaj's legacy transcends time, geography and religion. He proved that a small kingdom, with the right leadership and the will of its people, could stand against the mightiest empires on earth — the Mughal Empire, the Bijapur Sultanate, the Golconda Sultanate, the Siddi Navy, and even the Portuguese and British sea powers.</p>\r\n\r\n      <p class=\"legacy-para\">He was not merely a warrior — he was a statesman, an administrator, a naval strategist, a linguist, and a philosopher of governance. His Ashtapradhan system, his revenue reforms, his treatment of women and prisoners of war, his respect for all religions — these were centuries ahead of their time.</p>\r\n\r\n      <div class=\"legacy-quote\" style=\"border-left-color:var(--gold);border-right-color:var(--saffron);\">\r\n        <p class=\"legacy-quote-text\">\"The life of Chhatrapati Shivaji has been a source of inspiration to countless generations of Indians. He showed that it is possible to combine military genius with political wisdom, and personal bravery with administrative skill.\"</p>\r\n        <div class=\"legacy-quote-source\">— Bal Gangadhar Tilak, Father of Indian Nationalism</div>\r\n      </div>\r\n\r\n      <p class=\"legacy-para\">Bal Gangadhar Tilak revived the tradition of Shiv Jayanti (Chhatrapati Chhatrapati Shivaji's birthday celebration) in 1893 to use it as a unifying force for the Indian independence movement. Mahatma Gandhi, Subhas Chandra Bose, and countless freedom fighters drew inspiration from Chhatrapati Chhatrapati Shivaji's example. Today, the Indian Navy's motto — <em style=\"color:var(--saffron)\">\"Sha No Varuna\"</em> — carries forward the naval tradition Chhatrapati Shivaji began.</p>\r\n\r\n      <div style=\"background:linear-gradient(135deg,rgba(255,107,0,0.08),rgba(212,160,23,0.08));border:1px solid rgba(212,160,23,0.2);padding:50px;margin-top:40px;\">\r\n        <h3 style=\"font-family:'Cinzel Decorative',serif;color:var(--gold);font-size:1.5rem;text-align:center;margin-bottom:30px;\">जय भवानी! जय शिवाजी!</h3>\r\n        <p style=\"font-family:'EB Garamond',serif;font-size:1.3rem;font-style:italic;text-align:center;color:var(--cream-light);line-height:1.8;\">\r\n          \"He was a king, a warrior, a judge — but above all, he was a servant of his people. In an age of ruthless power politics, he chose humanity. In an age of religious persecution, he chose justice. In an age of despair, he chose hope — and called it Swarajya.\"\r\n        </p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</section>\n\n<!-- GUESTBOOK -->\n<section id=\"guestbook\">\n  <div class=\"section-container\">\n    <div class=\"section-header reveal\">\n      <span class=\"section-label\">Fullstack</span>\n      <h2 class=\"section-title\">Visitor Guestbook</h2>\n      <div class=\"section-divider\"></div>\n      <p class=\"section-desc\">Messages are saved through the Node backend and loaded back from the API</p>\n    </div>\n\n    <div class=\"guestbook-shell reveal\">\n      <div class=\"api-panel\">\n        <h3>Live API Data</h3>\n        <ul class=\"api-list\">\n          <li><strong>Title</strong><span id=\"apiTitle\">Loading...</span></li>\n          <li><strong>Years</strong><span id=\"apiYears\">Loading...</span></li>\n          <li><strong>Chapters</strong><span id=\"apiChapters\">Loading...</span></li>\n        </ul>\n      </div>\n\n      <div>\n        <form class=\"guestbook-form\" id=\"guestbookForm\">\n          <h3>Leave a Tribute</h3>\n          <div class=\"guestbook-fields\">\n            <input id=\"guestName\" name=\"name\" type=\"text\" maxlength=\"60\" placeholder=\"Your name\" required>\n            <textarea id=\"guestMessage\" name=\"message\" maxlength=\"240\" placeholder=\"Your message\" required></textarea>\n            <button type=\"submit\">Post Message</button>\n            <p class=\"guestbook-status\" id=\"guestbookStatus\"></p>\n          </div>\n        </form>\n        <div class=\"guestbook-list\" id=\"guestbookList\"></div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <span class=\"footer-emblem\"></span>\r\n  <div class=\"footer-title\">Chhatrapati Shivaji Maharaj</div>\r\n  <div class=\"footer-sub\">1630 — 1680 · Maratha Empire</div>\r\n  <div class=\"footer-slogan\">\r\n    \"जय भवानी! जय शिवाजी!\" — Victory to the Goddess! Victory to Chhatrapati Shivaji!\r\n  </div>\r\n  <div class=\"footer-links\">\r\n    <a href=\"#hero\">Home</a>\r\n    <a href=\"#early-life\">Early Life</a>\r\n    <a href=\"#timeline\">Timeline</a>\r\n    <a href=\"#battles\">Battles</a>\r\n    <a href=\"#forts\">Forts</a>\r\n    <a href=\"#coronation\">Coronation</a>\r\n    <a href=\"#achievements\">Achievements</a>\n    <a href=\"#videos\">Videos</a>\n    <a href=\"#legacy\">Legacy</a>\n    <a href=\"#guestbook\">Guestbook</a>\n  </div>\n  <div class=\"footer-copy\">\r\n    A tribute to the greatest warrior-king of Maharashtra · Built with reverence and pride\r\n  </div>\r\n</footer>";

export function runLegacyInteractions() {

  // Custom cursor
  const cursor = document.getElementById('cursor');
  const dot = document.getElementById('cursorDot');
  let mouseX = 0, mouseY = 0;
  let curX = 0, curY = 0;

  document.addEventListener('mousemove', (e) => {
    mouseX = e.clientX;
    mouseY = e.clientY;
    dot.style.left = mouseX + 'px';
    dot.style.top = mouseY + 'px';
  });

  function animateCursor() {
    curX += (mouseX - curX) * 0.12;
    curY += (mouseY - curY) * 0.12;
    cursor.style.left = curX + 'px';
    cursor.style.top = curY + 'px';
    requestAnimationFrame(animateCursor);
  }
  animateCursor();

  // Particle trail on click
  document.addEventListener('click', (e) => {
    for(let i = 0; i < 8; i++) {
      const p = document.createElement('div');
      p.className = 'particle';
      p.style.left = e.clientX + 'px';
      p.style.top = e.clientY + 'px';
      const angle = (i / 8) * Math.PI * 2;
      const dist = 40 + Math.random() * 60;
      p.style.setProperty('--tx', Math.cos(angle) * dist + 'px');
      p.style.setProperty('--ty', Math.sin(angle) * dist + 'px');
      p.style.background = i % 2 === 0 ? '#FF6B00' : '#FFD700';
      document.body.appendChild(p);
      setTimeout(() => p.remove(), 1500);
    }
  });

  // Scroll reveal
  const revealElements = document.querySelectorAll('.reveal, .reveal-left, .reveal-right');
  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry, index) => {
      if (entry.isIntersecting) {
        setTimeout(() => {
          entry.target.classList.add('visible');
        }, 100);
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -50px 0px' });

  revealElements.forEach(el => observer.observe(el));

  // Stagger children in grids
  document.querySelectorAll('.battles-grid, .forts-grid, .achievements-grid, .videos-grid').forEach(grid => {
    const children = grid.querySelectorAll('.reveal, .battle-card, .fort-card, .achievement-card, .video-wrap');
    children.forEach((child, i) => {
      child.style.transitionDelay = (i * 0.1) + 's';
    });
  });

  // Navbar scroll effect
  window.addEventListener('scroll', () => {
    const nav = document.querySelector('nav');
    if(window.scrollY > 100) {
      nav.style.background = 'rgba(13,5,0,0.97)';
      nav.style.borderBottom = '1px solid rgba(212,160,23,0.2)';
    } else {
      nav.style.background = 'linear-gradient(180deg,rgba(13,5,0,0.98) 0%,rgba(13,5,0,0) 100%)';
      nav.style.borderBottom = '1px solid rgba(212,160,23,0.15)';
    }
  });

  // Fullstack API integration
  const apiTitle = document.getElementById('apiTitle');
  const apiYears = document.getElementById('apiYears');
  const apiChapters = document.getElementById('apiChapters');
  const guestbookForm = document.getElementById('guestbookForm');
  const guestbookList = document.getElementById('guestbookList');
  const guestbookStatus = document.getElementById('guestbookStatus');

  function escapeHtml(value) {
    return value.replace(/[&<>"']/g, (char) => ({
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#039;'
    }[char]));
  }

  function formatDate(value) {
    return new Intl.DateTimeFormat('en-IN', {
      day: 'numeric',
      month: 'short',
      year: 'numeric'
    }).format(new Date(value));
  }

  async function loadSiteInfo() {
    if (!apiTitle || !apiYears || !apiChapters) return;
    const response = await fetch('/api/site');
    const data = await response.json();
    apiTitle.textContent = data.title;
    apiYears.textContent = data.years;
    apiChapters.textContent = data.chapters.length;
  }

  async function loadGuestbook() {
    if (!guestbookList) return;
    const response = await fetch('/api/guestbook');
    const entries = await response.json();
    guestbookList.innerHTML = entries.map((entry) => `
      <article class="guestbook-entry">
        <div class="guestbook-entry-head">
          <span>${escapeHtml(entry.name)}</span>
          <time datetime="${entry.createdAt}">${formatDate(entry.createdAt)}</time>
        </div>
        <p>${escapeHtml(entry.message)}</p>
      </article>
    `).join('');
  }

  if (guestbookForm) {
  guestbookForm.addEventListener('submit', async (event) => {
    event.preventDefault();
    guestbookStatus.textContent = 'Saving...';

    const formData = new FormData(guestbookForm);
    const payload = {
      name: formData.get('name'),
      message: formData.get('message')
    };

    const response = await fetch('/api/guestbook', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      const error = await response.json();
      guestbookStatus.textContent = error.error || 'Could not save your message.';
      return;
    }

    guestbookForm.reset();
    guestbookStatus.textContent = 'Message saved.';
    await loadGuestbook();
  });
  }

  loadSiteInfo().catch(() => {
    if (!apiTitle || !apiYears || !apiChapters) return;
    apiTitle.textContent = 'API unavailable';
    apiYears.textContent = '-';
    apiChapters.textContent = '-';
  });

  loadGuestbook().catch(() => {
    if (!guestbookStatus) return;
    guestbookStatus.textContent = 'Guestbook API is unavailable.';
  });

  // Hover effect on links
  document.querySelectorAll('a').forEach(a => {
    a.addEventListener('mouseenter', () => {
      cursor.style.transform = 'translate(-50%,-50%) scale(1.5)';
      cursor.style.borderColor = '#FFD700';
    });
    a.addEventListener('mouseleave', () => {
      cursor.style.transform = 'translate(-50%,-50%) scale(1)';
      cursor.style.borderColor = '#FF6B00';
    });
  });

  // Battle cards hover cursor
  document.querySelectorAll('.battle-card, .fort-card, .achievement-card').forEach(card => {
    card.addEventListener('mouseenter', () => {
      cursor.style.transform = 'translate(-50%,-50%) scale(2)';
      cursor.style.background = 'rgba(255,107,0,0.1)';
    });
    card.addEventListener('mouseleave', () => {
      cursor.style.transform = 'translate(-50%,-50%) scale(1)';
      cursor.style.background = 'transparent';
    });
  });

}
